/**
 * Types common to the [ElevationProfileAnalysisView2D](https://developers.arcgis.com/javascript/latest/references/core/views/2d/analysis/ElevationProfileAnalysisView2D/) and
 * [ElevationProfileAnalysisView3D](https://developers.arcgis.com/javascript/latest/references/core/views/3d/analysis/ElevationProfileAnalysisView3D/).
 *
 * @since 5.0
 */
import type Graphic from "../../../Graphic.js";
import type { LengthUnit } from "../../../core/units.js";

/** Represents a single sampled point along the generated elevation profile. */
export interface ElevationProfileSample {
  /** The x coordinate of the sample, in the spatial reference of the view. */
  readonly x: number;
  /** The y coordinate of the sample, in the spatial reference of the view. */
  readonly y: number;
  /** The z coordinate of the sample, in the spatial reference of the view. */
  readonly z?: number | null;
  /**
   * Horizontal (2D) distance from the beginning of the path, expressed in the effective units selected for the
   * analysis. In geographic coordinate systems (GCS) and WebMercator, the value is the geodesic distance. In projected
   * coordinate systems (PCS) other than WebMercator, the value is calculated using Euclidean distance in the PCS.
   */
  readonly distance: number;
  /** The elevation of the sample, in the effective units selected by the user. */
  readonly elevation?: number | null;
}

/** Combined statistics of all the computed elevation profile lines. */
export interface ElevationProfileStatistics {
  /**
   * The maximum horizontal (2D) distance of the path. In geographic
   * coordinate systems (GCS) and in WebMercator, the distance is the geodesic distance. In projected
   * coordinate systems (PCS), apart from WebMercator, the distance is computed in a Euclidean manner
   * (in the respective PCS).
   */
  readonly maxDistance?: number | null;
  /** The minimum elevation along the path. */
  readonly minElevation?: number | null;
  /** The maximum elevation along the path. */
  readonly maxElevation?: number | null;
  /** The average elevation along the path. */
  readonly avgElevation?: number | null;
  /**
   * The cumulative elevation gain along the path.
   * See https://en.wikipedia.org/wiki/Cumulative_elevation_gain
   */
  readonly elevationGain?: number | null;
  /**
   * The cumulative elevation loss along the path.
   * See https://en.wikipedia.org/wiki/Cumulative_elevation_gain
   */
  readonly elevationLoss?: number | null;
  /**
   * The maximum positive slope along the path. Profiles are sampled at a
   *   minimum distance of 10 meters (32.8 feet). Higher resolution profiles are downsampled to that minimum sampling
   *   distance before calculating the slope.
   */
  readonly maxPositiveSlope?: number | null;
  /**
   * The maximum negative slope along the path. Profiles are sampled at a
   *   minimum distance of 10 meters (32.8 feet). Higher resolution profiles are downsampled to that minimum sampling
   *   distance before calculating the slope.
   */
  readonly maxNegativeSlope?: number | null;
  /**
   * The average positive slope along the path. Profiles are sampled at a
   *   minimum distance of 10 meters (32.8 feet). Higher resolution profiles are downsampled to that minimum sampling
   *   distance before calculating the slope.
   */
  readonly avgPositiveSlope?: number | null;
  /**
   * The average negative slope along the path. Profiles are sampled at a
   *   minimum distance of 10 meters (32.8 feet). Higher resolution profiles are downsampled to that minimum sampling
   *   distance before calculating the slope.
   */
  readonly avgNegativeSlope?: number | null;
}

/** Result of interactively placing an elevation profile line on the view. */
export interface ElevationProfilePlacementResult {}

/** Result of picking a feature from the view to perform an elevation profile analysis. */
export interface ElevationProfilePickResult {
  /** The picked feature. */
  feature: Graphic;
}

/**
 * Effective units for the elevation profile analysis, determined from the magnitudes of all computed values and the
 * display preferences selected by the user.
 */
export interface ElevationProfileEffectiveDisplayUnits {
  /** The effective distance unit used for the results and statistics of the elevation profile analysis. */
  readonly distance: LengthUnit;
  /** The effective elevation unit used for the results and statistics of the elevation profile analysis. */
  readonly elevation: LengthUnit;
}